#include <bits/stdc++.h>
using namespace std;

void mi(int n){
    int sum=0,tmp=n;bool a[32];
    while(tmp){
        if(tmp%2)a[sum++]=true;
        else a[sum++]=false;
        tmp/=2;
    }
    //for(int i=0;i<sum;i++)cout<<a[i]<<' ';
    //cout<<endl;
    bool first=true;
    for(int i=sum-1;i>=0;i--){
        if(a[i]){
            if(!first)cout<<'+';
            else first=false;
            if(i==0)cout<<"2(0)";
            else if(i==1)cout<<2;
            else{
                cout<<"2(";
                mi(i);
                cout<<")";
            }
        }
    }
}

int main(){
	int n;
    cin>>n;
    mi(n);
    return 0;
}
